1	type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	type Customer = { yearsWithMHPCO: number };
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	
12	type Damage = { itemType: string; amount: number };
13	
14	type ClaimStep = {
15	  op: "claim";
16	  policy: number;
17	  incident: { cause: string; damages: Damage[] };
18	};
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	type Scenario = {
23	  customer: Customer;
24	  steps: Step[];
25	};
26	
27	type ScenarioResult = {
28	  results: { premium?: number; payout?: number; remainingCap?: number }[];
29	};
30	
31	const PROCESSING_FEE = 5;
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	
35	const firstInsuranceSurcharge = (premium: number): number =>
36	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
37	
38	const COMPONENT_PREMIUM = 25;
39	
40	const BASE_PREMIUMS: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: COMPONENT_PREMIUM,
46	  moonstone: COMPONENT_PREMIUM,
47	};
48	
49	const BLOCK_PREMIUM = 60;
50	
51	const isBlock = (count: number): boolean => count === 3;
52	
53	const countByType = (items: Item[]): Record<string, number> =>
54	  items.reduce<Record<string, number>>((counts, item) => {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	    return counts;
57	  }, {});
58	
59	const premiumForGroup = (type: string, count: number): number =>
60	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
61	
62	const basePremiumFor = (items: Item[]): number =>
63	  Object.entries(countByType(items)).reduce(
64	    (total, [type, count]) => total + premiumForGroup(type, count),
65	    0,
66	  );
67	
68	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
69	
70	const sumBy = (items: Item[], valueOf: (item: Item) => number): number =>
71	  items.reduce((total, item) => total + valueOf(item), 0);
72	
73	const surchargeFor = (
74	  items: Item[],
75	  qualifies: (item: Item) => boolean,
76	  rate: number,
77	): number =>
78	  sumBy(items, (item) =>
79	    qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0,
80	  );
81	
82	const CURSE_SURCHARGE_RATE = 0.5;
83	
84	const isCursed = (item: Item): boolean => item.cursed === true;
85	
86	const curseSurchargeFor = (items: Item[]): number =>
87	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
88	
89	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
90	
91	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
92	
93	const isHighlyEnchanted = (item: Item): boolean =>
94	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
95	
96	const enchantmentSurchargeFor = (items: Item[]): number =>
97	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
98	
99	const discountFor = (
100	  qualifies: boolean,
101	  premium: number,
102	  rate: number,
103	): number => (qualifies ? premium * rate : 0);
104	
105	const LOYALTY_DISCOUNT_RATE = 0.2;
106	
107	const LOYALTY_YEARS_THRESHOLD = 2;
108	
109	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
110	  discountFor(
111	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
112	    premium,
113	    LOYALTY_DISCOUNT_RATE,
114	  );
115	
116	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
117	
118	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
119	  discountFor(isFollowUp, premium, FOLLOW_UP_DISCOUNT_RATE);
120	
121	const quotePremium = (
122	  customer: Customer,
123	  items: Item[],
124	  isFollowUp: boolean,
125	): number => {
126	  const basePremium = basePremiumFor(items);
127	  return roundUpToWholeGold(
128	    basePremium +
129	      curseSurchargeFor(items) +
130	      enchantmentSurchargeFor(items) +
131	      firstInsuranceSurcharge(basePremium) -
132	      loyaltyDiscountFor(customer, basePremium) -
133	      followUpDiscountFor(isFollowUp, basePremium) +
134	      PROCESSING_FEE,
135	  );
136	};
137	
138	const DEDUCTIBLE = 100;
139	
140	const HIGH_ENCHANTMENT_THRESHOLD = 8;
141	
142	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
143	
144	const reimbursementRateFor = (item: Item | undefined): number =>
145	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
146	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
147	    : 1;
148	
149	const payoutForDamage = (insuredItems: Item[], damage: Damage): number => {
150	  const insuredItem = insuredItems.find(
151	    (item) => item.type === damage.itemType,
152	  );
153	  return damage.amount * reimbursementRateFor(insuredItem) - DEDUCTIBLE;
154	};
155	
156	const insuredItemsForPolicy = (steps: Step[], policy: number): Item[] => {
157	  const policyStep = steps[policy];
158	  return policyStep.op === "quote" ? policyStep.items : [];
159	};
160	
161	const claimPayout = (insuredItems: Item[], damages: Damage[]): number =>
162	  damages.reduce(
163	    (total, damage) => total + payoutForDamage(insuredItems, damage),
164	    0,
165	  );
166	
167	const INSURANCE_VALUES: Record<string, number> = {
168	  sword: 1000,
169	  amulet: 600,
170	  rune: 250,
171	};
172	
173	const CAP_MULTIPLIER = 2;
174	
175	const insuranceSumFor = (items: Item[]): number =>
176	  sumBy(items, (item) => INSURANCE_VALUES[item.type]);
177	
178	const remainingCapFor = (insuredItems: Item[], totalPaid: number): number =>
179	  CAP_MULTIPLIER * insuranceSumFor(insuredItems) - totalPaid;
180	
181	const claimResult = (
182	  steps: Step[],
183	  step: ClaimStep,
184	  alreadyPaid: number,
185	): { payout: number; remainingCap: number } => {
186	  const insuredItems = insuredItemsForPolicy(steps, step.policy);
187	  const payout = Math.floor(
188	    Math.min(
189	      claimPayout(insuredItems, step.incident.damages),
190	      remainingCapFor(insuredItems, alreadyPaid),
191	    ),
192	  );
193	  return {
194	    payout,
195	    remainingCap: remainingCapFor(insuredItems, alreadyPaid + payout),
196	  };
197	};
198	
199	export const runScenario = (scenario: Scenario): ScenarioResult => {
200	  const paidByPolicy: Record<number, number> = {};
201	  return {
202	    results: scenario.steps.map((step, index) => {
203	      if (step.op === "quote") {
204	        return {
205	          premium: quotePremium(scenario.customer, step.items, index > 0),
206	        };
207	      }
208	      const alreadyPaid = paidByPolicy[step.policy] ?? 0;
209	      const result = claimResult(scenario.steps, step, alreadyPaid);
210	      paidByPolicy[step.policy] = alreadyPaid + result.payout;
211	      return result;
212	    }),
213	  };
214	};
